exercises.solution_code:
#include <iostream>
#include <iomanip>

struct Rectangle
{
    double width;
    double height;
};

double area(Rectangle r)
{
    return r.width * r.height;
}

int main()
{
    Rectangle r1;
    Rectangle r2;

    std::cin >> r1.width >> r1.height;
    std::cin >> r2.width >> r2.height;

    std::cout << std::fixed << std::setprecision(1);

    std::cout << "Rectangle 1: " << r1.width << " x " << r1.height
              << ", area = " << area(r1) << '\n';
    std::cout << "Rectangle 2: " << r2.width << " x " << r2.height
              << ", area = " << area(r2) << '\n';

    return 0;
}

